import { motion, animate, useMotionValue, useTransform } from "framer-motion";
import { useEffect } from "react";

const logoSrc = "data:image/webp;base64,";

const fadeUp = {
  hidden: { opacity: 0, y: 26 },
  show: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.65, ease: "easeOut" },
  },
};

const stagger = {
  hidden: {},
  show: {
    transition: { staggerChildren: 0.1 },
  },
};

function CountUpStat({ target, suffix = "", duration = 1.8 }) {
  const count = useMotionValue(0);
  const rounded = useTransform(count, (latest) => Math.floor(latest));

  useEffect(() => {
    const controls = animate(count, target, { duration, ease: "easeOut" });
    return () => controls.stop();
  }, [count, duration, target]);

  return <motion.span>{rounded}</motion.span>;
}

function CircularRiskMeter({ value = 78 }) {
  const radius = 58;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (value / 100) * circumference;

  return (
    <div className="relative mx-auto flex h-[170px] w-[170px] items-center justify-center">
      <svg className="absolute inset-0 -rotate-90" viewBox="0 0 140 140">
        <circle cx="70" cy="70" r={radius} stroke="rgba(255,255,255,0.08)" strokeWidth="10" fill="none" />
        <motion.circle
          cx="70"
          cy="70"
          r={radius}
          stroke="url(#riskGradient)"
          strokeWidth="10"
          fill="none"
          strokeLinecap="round"
          strokeDasharray={circumference}
          initial={{ strokeDashoffset: circumference }}
          whileInView={{ strokeDashoffset }}
          viewport={{ once: true }}
          transition={{ duration: 1.4, ease: "easeOut" }}
        />
        <defs>
          <linearGradient id="riskGradient" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#22d3ee" />
            <stop offset="100%" stopColor="#8b5cf6" />
          </linearGradient>
        </defs>
      </svg>
      <div className="relative z-10 text-center">
        <div className="text-xs uppercase tracking-[0.2em] text-white/45">Risk Score</div>
        <div className="mt-2 text-4xl font-bold text-white">
          <CountUpStat target={value} />%
        </div>
        <div className="mt-1 text-sm text-violet-200">High Risk</div>
      </div>
      <div className="absolute inset-5 rounded-full bg-[radial-gradient(circle,rgba(34,211,238,0.12),transparent_60%)] blur-xl" />
    </div>
  );
}

